#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) % 3 for _ in range(N)]
        best = 10**18
        for first in range(3):
            for second in range(3):
                cost = first + second
                prev2, prev1 = first, second
                for i in range(N - 2):
                    need = -(a[i] + prev2 + a[i+1] + prev1 + a[i+2])
                    need %= 3
                    cost += need
                    prev2, prev1 = prev1, need
                if cost < best:
                    best = cost
        out_lines.append(str(best))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

